import{_ as a,o as i,c as t,ag as e}from"./chunks/framework.DvSl3FxN.js";const c=JSON.parse('{"title":"风格指南","description":"","frontmatter":{"title":"风格指南"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/style-guide.md","filePath":"novels/jin-gu-yao/behind-the-scenes/style-guide.md","lastUpdated":1773897450000}'),o={name:"novels/jin-gu-yao/behind-the-scenes/style-guide.md"};function r(n,l,h,u,s,d){return i(),t("div",null,[...l[0]||(l[0]=[e('<h1 id="风格指南-—-马伯庸式历史小说" tabindex="-1">风格指南 — 马伯庸式历史小说 <a class="header-anchor" href="#风格指南-—-马伯庸式历史小说" aria-label="Permalink to &quot;风格指南 — 马伯庸式历史小说&quot;">​</a></h1><h2 id="一、马伯庸核心风格特征" tabindex="-1">一、马伯庸核心风格特征 <a class="header-anchor" href="#一、马伯庸核心风格特征" aria-label="Permalink to &quot;一、马伯庸核心风格特征&quot;">​</a></h2><h3 id="_1-大事不虚-小事不拘" tabindex="-1">1. &quot;大事不虚，小事不拘&quot; <a class="header-anchor" href="#_1-大事不虚-小事不拘" aria-label="Permalink to &quot;1. &quot;大事不虚，小事不拘&quot;&quot;">​</a></h3><ul><li>核心历史事件和走向忠于史实</li><li>细节、人物心理、日常生活大胆虚构</li><li>用考据精神构建可信的世界，用想象力填充历史缝隙</li></ul><h3 id="_2-现代感与古典美交融" tabindex="-1">2. 现代感与古典美交融 <a class="header-anchor" href="#_2-现代感与古典美交融" aria-label="Permalink to &quot;2. 现代感与古典美交融&quot;">​</a></h3><ul><li>语言不模仿古文，用现代白话写历史</li><li>但遣词用句有质感，避免网文式的轻浮</li><li>人物思维方式带有现代人能共情的逻辑，但行为受制于时代规则</li></ul><h3 id="_3-小人物大历史-视角" tabindex="-1">3. &quot;小人物大历史&quot;视角 <a class="header-anchor" href="#_3-小人物大历史-视角" aria-label="Permalink to &quot;3. &quot;小人物大历史&quot;视角&quot;">​</a></h3><ul><li>善于从底层/边缘人物的视角切入宏大历史</li><li>《长安的荔枝》：一个底层小吏被迫完成不可能的任务</li><li>《显微镜下的大明》：普通百姓的税务官司折射帝国运作</li><li><strong>对我们的启示</strong>：虽然公主是主角，但可以通过她身边的人（马三宝、普通士兵、村妇）来展现更丰富的视角</li></ul><h3 id="_4-调度复杂的叙事能力" tabindex="-1">4. 调度复杂的叙事能力 <a class="header-anchor" href="#_4-调度复杂的叙事能力" aria-label="Permalink to &quot;4. 调度复杂的叙事能力&quot;">​</a></h3><ul><li>多条线索并行推进</li><li>人物、关系、事件高效整合在有限时空</li><li>每个人物的每个行动都有合理依据</li><li>制造&quot;出人意料但合情合理&quot;的反转</li></ul><h3 id="_5-幽默感" tabindex="-1">5. 幽默感 <a class="header-anchor" href="#_5-幽默感" aria-label="Permalink to &quot;5. 幽默感&quot;">​</a></h3><ul><li>冷幽默为主，不是段子式搞笑</li><li>幽默来自角色性格和处境的反差</li><li>严肃场景中突然冒出的人性化瞬间</li><li>例：张小敬要死了还想着吃东西；柴绍被围困时让美女跳舞</li></ul><h3 id="_6-专业性与可读性平衡" tabindex="-1">6. 专业性与可读性平衡 <a class="header-anchor" href="#_6-专业性与可读性平衡" aria-label="Permalink to &quot;6. 专业性与可读性平衡&quot;">​</a></h3><ul><li>大量考据细节（地理、官制、器物、风俗）</li><li>但不掉书袋，细节服务于故事推进</li><li>读者在不知不觉中学到历史知识</li></ul><hr><h2 id="二、叙事节奏" tabindex="-1">二、叙事节奏 <a class="header-anchor" href="#二、叙事节奏" aria-label="Permalink to &quot;二、叙事节奏&quot;">​</a></h2><h3 id="章节结构" tabindex="-1">章节结构 <a class="header-anchor" href="#章节结构" aria-label="Permalink to &quot;章节结构&quot;">​</a></h3><ul><li>每章3000-5000字</li><li>开头：快速切入场景，不做冗长铺垫</li><li>中段：推进情节 + 插入细节/幽默</li><li>结尾：留悬念或情感钩子</li><li><strong>马伯庸的节奏感</strong>：紧-松-紧，像呼吸一样。不会连续三章都是打仗，也不会连续三章都在聊天</li></ul><h3 id="时间感" tabindex="-1">时间感 <a class="header-anchor" href="#时间感" aria-label="Permalink to &quot;时间感&quot;">​</a></h3><ul><li>马伯庸喜欢用精确的时间推进叙事（《长安十二时辰》极端例子）</li><li>我们不需要这么极端，但每章应该让读者知道&quot;现在是什么时候&quot;</li><li>大事件之间的时间跳跃要自然过渡</li></ul><hr><h2 id="三、语言风格" tabindex="-1">三、语言风格 <a class="header-anchor" href="#三、语言风格" aria-label="Permalink to &quot;三、语言风格&quot;">​</a></h2><h3 id="对话" tabindex="-1">对话 <a class="header-anchor" href="#对话" aria-label="Permalink to &quot;对话&quot;">​</a></h3><ul><li>不用&quot;古白话&quot;（避免&quot;小生&quot;&quot;奴家&quot;&quot;在下&quot;这类套路）</li><li>也不用完全现代口语</li><li>找一个中间地带：简洁、有力、带性格</li><li>每个角色有自己的说话方式</li></ul><h3 id="描写" tabindex="-1">描写 <a class="header-anchor" href="#描写" aria-label="Permalink to &quot;描写&quot;">​</a></h3><ul><li>环境描写克制，点到为止，服务于氛围</li><li>动作描写干脆利落，不拖泥带水</li><li>心理描写用行动和细节暗示，少用&quot;她想&quot;&quot;她觉得&quot;</li></ul><h3 id="示例风格-我们的目标调性" tabindex="-1">示例风格（我们的目标调性） <a class="header-anchor" href="#示例风格-我们的目标调性" aria-label="Permalink to &quot;示例风格（我们的目标调性）&quot;">​</a></h3><p><strong>不要这样写：</strong></p><blockquote><p>平阳公主心想，丈夫已经离去，自己必须独自面对这一切。她觉得很害怕，但又很坚定。她下定决心，一定要为父亲的大业做出贡献。</p></blockquote><p><strong>要这样写：</strong></p><blockquote><p>柴绍走后第三天，她把头发束起来，换上男装，在铜镜前端详了自己许久。镜中的人看起来像个清瘦的少年，只是眉眼间多了些不属于少年的东西。她把镜子扣过去，出了门。</p></blockquote><hr><h2 id="四、幽默元素指南" tabindex="-1">四、幽默元素指南 <a class="header-anchor" href="#四、幽默元素指南" aria-label="Permalink to &quot;四、幽默元素指南&quot;">​</a></h2><h3 id="幽默的来源-适合我们故事的" tabindex="-1">幽默的来源（适合我们故事的） <a class="header-anchor" href="#幽默的来源-适合我们故事的" aria-label="Permalink to &quot;幽默的来源（适合我们故事的）&quot;">​</a></h3><ol><li><strong>身份反差</strong> — 贵族千金变成山寨头领，习惯性的优雅与粗犷现实的碰撞</li><li><strong>将军与母亲</strong> — 刚下令斩杀逃兵，转身发现儿子把军旗当尿布用了</li><li><strong>古今认知差</strong> — 用现代人能理解的逻辑去处理古代困境，产生微妙的幽默感</li><li><strong>配角的人间烟火</strong> — 马三宝的碎碎念、士兵们私下的八卦</li><li><strong>柴绍的&quot;无奈&quot;</strong> — 发现自己老婆比自己能打，战功比自己多</li></ol><h3 id="幽默的分寸" tabindex="-1">幽默的分寸 <a class="header-anchor" href="#幽默的分寸" aria-label="Permalink to &quot;幽默的分寸&quot;">​</a></h3><ul><li>不能破坏历史感和人物厚度</li><li>笑完之后要有余味，不是纯搞笑</li><li>频率：大约每1000-1500字一个轻松点，不要密集</li><li>关键的生死场景不插入幽默</li></ul><hr><h2 id="五、与马伯庸的差异化" tabindex="-1">五、与马伯庸的差异化 <a class="header-anchor" href="#五、与马伯庸的差异化" aria-label="Permalink to &quot;五、与马伯庸的差异化&quot;">​</a></h2><p>我们不是在复制马伯庸，而是以他的风格为基底，加入自己的特色：</p><ol><li><strong>更强的女性视角</strong> — 马伯庸作品中女性角色通常不是第一主角，我们是</li><li><strong>更多情感厚度</strong> — 马伯庸偏重智性（解谜、博弈），我们在此基础上加入母性、夫妻关系、自我认同</li><li><strong>幽默更生活化</strong> — 马伯庸的幽默偏文人式冷幽默，我们可以加入更接地气的生活幽默</li><li><strong>节奏更适合连载</strong> — 每章独立可读，但连起来是完整的弧线</li></ol><hr><h2 id="六、禁忌清单" tabindex="-1">六、禁忌清单 <a class="header-anchor" href="#六、禁忌清单" aria-label="Permalink to &quot;六、禁忌清单&quot;">​</a></h2><ul><li>❌ 不写&quot;玛丽苏&quot;式的万能女主</li><li>❌ 不写无脑打脸爽文</li><li>❌ 不用网文套路（金手指、系统、穿越）</li><li>❌ 不过度美化历史人物</li><li>❌ 不用&quot;古装言情&quot;的腔调</li><li>❌ 不回避历史的残酷面（但不是为了猎奇）</li><li>❌ 不让幽默盖过故事本身的分量</li></ul>',44)])])}const b=a(o,[["render",r]]);export{c as __pageData,b as default};
